import React, { useRef } from 'react';
import './contact.css'
import { MdOutlineEmail } from 'react-icons/md'
import { RiMessengerLine } from 'react-icons/ri'
import { RiMediumLine } from 'react-icons/ri'
import { RiWhatsappLine } from 'react-icons/ri'
import emailjs from 'emailjs-com';

export const Contact = () => {
  const form = useRef();

  const sendEmail = (e) => {
    e.preventDefault();

    emailjs.sendForm('service_n1eeqoi', 'template_ldhkcx4', form.current, 'LjMakTvDbo-DQ_Fbh')
      .then((result) => {
          console.log(result.text);
      }, (error) => {
          console.log(error.text);
      });

    e.target.reset();
    };


  return (
    <section id="contact">
      <h5>Get In Touch</h5>
      <h2>Contact Me</h2>
      <div className="container contact__container">
        <div className="contact__options">
          <article className="contact__option">
            <RiMessengerLine className="contact__option-icon"/>
            <h4>Messenger</h4>
            <h5>Natalie Lee</h5>
            <a href="https://m.me/melody811118" target="_blank">Send a message</a>
          </article>
          <article className="contact__option">
            <MdOutlineEmail className="contact__option-icon"/>
            <h4>Email</h4>
            <h5>chiaenl@alumni.cmu.edu</h5>
            <a href="mailto:chiaenl@alumni.cmu.edu" target="_blank">Send a message</a>
          </article>
          <article className="contact__option">
            <RiWhatsappLine className="contact__option-icon"/>
            <h4>WhatsApp</h4>
            <h5>+2139739397</h5>
            <a href="https://web.whatsapp.com/send?phone=+12139739397" target="_blank">Send a message</a>
          </article>
          <article className="contact__option">
            <RiMediumLine className="contact__option-icon"/>
            <h4>Medium</h4>
            <h5>Natalie Lee</h5>
            <a href="" target="_blank">Visit Blog</a>
          </article>
        </div>
        <form ref={form} onSubmit={sendEmail}>
          <input type="text" name="name" placeholder="Your Full Name" required/>
          <input type="email" name="email" placeholder="Your Email" required/>
          <textarea name="message" rows="7" placeholde="Your Message" required></textarea>
          <button type="submit" className="btn btn-primary">Send Message</button>
        </form>
      </div>
    </section>
  )
}
